def execute(params):
    import os, re, subprocess, hashlib, shutil, time
    repo = (params.get('repo') or '').strip()
    if not repo:
        return {'success': False, 'error': 'repo required (owner/name, github URL, or git URL)'}
    ref = (params.get('ref') or '').strip()
    shallow = params.get('shallow', True) if params.get('shallow') is not None else True
    timeout_s = int(params.get('timeout_s') or 120)
    size_limit_mb = int(params.get('size_limit_mb') or 500)

    clone_url = repo
    if re.match(r'^[A-Za-z0-9._-]+/[A-Za-z0-9._-]+$', repo):
        clone_url = 'https://github.com/' + repo + '.git'
    elif 'github.com/' in repo and not repo.endswith('.git'):
        m = re.search(r'github\.com/([^/\s]+)/([^/\s#?]+)', repo)
        if m:
            clone_url = 'https://github.com/' + m.group(1) + '/' + m.group(2) + '.git'

    # Inside the sandbox, /workspace is bind-mounted from the host (per-user).
    # Outside the sandbox (legacy in-process path), fall back to /tmp.
    base_parent = '/workspace' if os.path.isdir('/workspace') else '/tmp'
    base_dir = os.path.join(base_parent, 'gh-clones')
    os.makedirs(base_dir, exist_ok=True)

    key = hashlib.sha1((clone_url + '|' + (ref or '')).encode()).hexdigest()[:12]
    target = os.path.join(base_dir, key)

    # TTL sweep: nuke sibling clones older than 24h (only inside base_dir).
    try:
        now = time.time()
        for name in os.listdir(base_dir):
            p = os.path.join(base_dir, name)
            try:
                if p != target and os.path.isdir(p) and now - os.path.getmtime(p) > 86400:
                    shutil.rmtree(p, ignore_errors=True)
            except Exception:
                pass
    except Exception:
        pass

    if os.path.isdir(os.path.join(target, '.git')):
        try:
            sha_r = subprocess.run(['git', '-C', target, 'rev-parse', 'HEAD'],
                                   capture_output=True, text=True, timeout=10)
            head_sha = sha_r.stdout.strip() if sha_r.returncode == 0 else None
        except Exception:
            head_sha = None
        return {
            'success': True,
            'cached': True,
            'repo': repo,
            'clone_url': clone_url,
            'path': target,
            'ref': ref or 'default',
            'head_sha': head_sha,
            'note': 'Already cloned. Use list_directory(path=...) / read_file(filePath=...) / git_list_tree(repoPath=...) on ' + target,
        }

    cmd = ['git', 'clone']
    if shallow:
        cmd += ['--depth', '1']
        if ref and re.match(r'^[0-9a-f]{7,40}$', ref):
            cmd += [clone_url, target]
        elif ref:
            cmd += ['--branch', ref, clone_url, target]
        else:
            cmd += [clone_url, target]
    else:
        cmd += [clone_url, target]

    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout_s)
    except subprocess.TimeoutExpired:
        shutil.rmtree(target, ignore_errors=True)
        return {'success': False, 'error': 'clone timed out after ' + str(timeout_s) + 's'}
    except Exception as e:
        shutil.rmtree(target, ignore_errors=True)
        return {'success': False, 'error': 'clone failed: ' + str(e)}
    if r.returncode != 0:
        shutil.rmtree(target, ignore_errors=True)
        return {'success': False, 'error': 'git clone failed: ' + (r.stderr or r.stdout)[:600]}

    if shallow and ref and re.match(r'^[0-9a-f]{7,40}$', ref):
        try:
            f = subprocess.run(
                ['git', '-C', target, 'fetch', '--depth', '1', 'origin', ref],
                capture_output=True, text=True, timeout=timeout_s,
            )
            if f.returncode != 0:
                subprocess.run(['git', '-C', target, 'fetch', '--unshallow'],
                               capture_output=True, text=True, timeout=timeout_s)
            co = subprocess.run(['git', '-C', target, 'checkout', ref],
                                capture_output=True, text=True, timeout=30)
            if co.returncode != 0:
                return {'success': False, 'error': 'checkout ' + ref + ' failed: ' + (co.stderr or co.stdout)[:400], 'path': target}
        except Exception as e:
            return {'success': False, 'error': 'fetch/checkout failed: ' + str(e), 'path': target}

    def dir_size_mb(p):
        total = 0
        for root, dirs, files in os.walk(p):
            for f in files:
                try:
                    total += os.path.getsize(os.path.join(root, f))
                except OSError:
                    pass
        return total / (1024 * 1024)
    size_mb = dir_size_mb(target)
    if size_mb > size_limit_mb:
        shutil.rmtree(target, ignore_errors=True)
        return {'success': False, 'error': 'clone exceeded size_limit_mb=' + str(size_limit_mb) + ' (was ' + str(round(size_mb, 1)) + ' MB)'}

    try:
        sha_r = subprocess.run(['git', '-C', target, 'rev-parse', 'HEAD'],
                               capture_output=True, text=True, timeout=10)
        head_sha = sha_r.stdout.strip() if sha_r.returncode == 0 else None
        br_r = subprocess.run(['git', '-C', target, 'rev-parse', '--abbrev-ref', 'HEAD'],
                              capture_output=True, text=True, timeout=10)
        branch = br_r.stdout.strip() if br_r.returncode == 0 else None
    except Exception:
        head_sha, branch = None, None

    file_count = 0
    for root, dirs, files in os.walk(target):
        if '.git' in dirs:
            dirs.remove('.git')
        file_count += len(files)

    return {
        'success': True,
        'cached': False,
        'repo': repo,
        'clone_url': clone_url,
        'path': target,
        'ref': ref or 'default',
        'head_sha': head_sha,
        'branch': branch,
        'file_count': file_count,
        'size_mb': round(size_mb, 2),
        'shallow': bool(shallow),
        'note': 'Clone is in the shared workspace. Use list_directory(path=...) to browse, read_file(filePath=...) to open, find_patterns on content, git_list_tree / git_log / git_show_commit / git_file_history / git_blame for git ops.',
    }

def execute(params):
    import subprocess, os
    repo_path = params.get('repoPath') or params.get('path_repo') or os.getcwd()
    if not os.path.isdir(repo_path):
        return {'success': False, 'error': 'repoPath not a directory: ' + str(repo_path)}
    ref = (params.get('ref') or 'HEAD').strip()
    sub_path = (params.get('path') or '').strip('/')
    recursive = True if params.get('recursive') is None else bool(params.get('recursive'))
    limit = int(params.get('limit') or 1000)
    if sub_path:
        if sub_path.startswith('/'):
            rp = os.sub_path.realpath(repo_path).rstrip('/')
            pp = os.sub_path.realpath(sub_path)
            if pp == rp:
                sub_path = '.'
            elif pp.startswith(rp + '/'):
                sub_path = pp[len(rp) + 1:]
            else:
                return {'success': False, 'error': 'sub_path must be repo-relative (e.g. "src/app.py" or "."), not absolute: ' + sub_path}
    cmd = ['git', '-C', repo_path, 'ls-tree', '--long']
    if recursive:
        cmd.append('-r')
    cmd.append(ref)
    if sub_path:
        cmd.append(sub_path)
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=60)
    except Exception as e:
        return {'success': False, 'error': 'ls-tree failed: ' + str(e)}
    if r.returncode != 0:
        return {'success': False, 'error': 'ls-tree: ' + (r.stderr or r.stdout)[:400]}
    entries = []
    for line in r.stdout.splitlines():
        # Format with --long: "<mode> <type> <sha> <size|-> \t<path>"
        if not line:
            continue
        try:
            meta, path = line.split('\t', 1)
            parts = meta.split()
            mode, obj_type, sha = parts[0], parts[1], parts[2]
            size = parts[3] if len(parts) > 3 else None
            try:
                size = int(size)
            except Exception:
                size = None
            entries.append({
                'path': path,
                'type': ('dir' if obj_type == 'tree' else 'file'),
                'mode': mode,
                'sha': sha[:10],
                'size': size,
            })
        except Exception:
            continue
    total = len(entries)
    truncated = total > limit
    return {
        'success': True,
        'repoPath': repo_path,
        'ref': ref,
        'root': sub_path or '/',
        'recursive': bool(recursive),
        'total': total,
        'count': min(total, limit),
        'truncated': truncated,
        'entries': entries[:limit],
    }

def execute(params):
    import subprocess, os, re
    repo_path = params.get('repoPath') or os.getcwd()
    sha = (params.get('sha') or params.get('commit') or '').strip()
    if not sha:
        return {'success': False, 'error': 'sha required'}
    if not os.path.isdir(repo_path):
        return {'success': False, 'error': 'repoPath not a directory: ' + str(repo_path)}
    include_patches = True if params.get('include_patches') is None else bool(params.get('include_patches'))
    max_patch = int(params.get('max_patch_chars') or 8000)

    # 1) Metadata via --pretty
    try:
        meta = subprocess.run(
            ['git', '-C', repo_path, 'show', '--no-patch', '--pretty=format:%H%n%an%n%ae%n%at%n%cn%n%ct%n%P%n%s%n%b%n---END---', sha],
            capture_output=True, text=True, timeout=30,
        )
    except Exception as e:
        return {'success': False, 'error': 'show failed: ' + str(e)}
    if meta.returncode != 0:
        return {'success': False, 'error': 'git show: ' + (meta.stderr or meta.stdout)[:400]}
    lines = meta.stdout.split('\n')
    # Subject is line index 7; body may span multiple lines until ---END---
    try:
        full_sha = lines[0]
        author = lines[1]
        author_email = lines[2]
        author_ts = int(lines[3]) if lines[3] else None
        committer = lines[4]
        committer_ts = int(lines[5]) if lines[5] else None
        parents = lines[6].split() if lines[6] else []
        subject = lines[7]
        body_lines = []
        for l in lines[8:]:
            if l == '---END---':
                break
            body_lines.append(l)
        body = '\n'.join(body_lines).strip()
    except IndexError:
        return {'success': False, 'error': 'could not parse git show output'}

    # 2) Per-file stats via --numstat
    try:
        ns = subprocess.run(
            ['git', '-C', repo_path, 'log', '-n', '1', '--numstat', '--format=', sha],
            capture_output=True, text=True, timeout=30,
        )
    except Exception as e:
        return {'success': False, 'error': 'numstat failed: ' + str(e)}
    files_map = {}  # path -> {additions, deletions}
    for line in ns.stdout.splitlines():
        if not line.strip():
            continue
        parts = line.split('\t')
        if len(parts) < 3:
            continue
        add, dele, path = parts[0], parts[1], parts[2]
        try:
            add = int(add) if add != '-' else None
            dele = int(dele) if dele != '-' else None
        except Exception:
            add, dele = None, None
        files_map[path] = {'filename': path, 'additions': add, 'deletions': dele, 'patch': None, 'patch_truncated': False}

    # 3) Patches (optional)
    if include_patches:
        try:
            pr = subprocess.run(
                ['git', '-C', repo_path, 'show', '--format=', sha],
                capture_output=True, text=True, timeout=60,
            )
            if pr.returncode == 0:
                current = None
                buf = []
                def flush():
                    if current and buf:
                        p = '\n'.join(buf)
                        truncated = False
                        if len(p) > max_patch:
                            p = p[:max_patch] + '\n... (truncated)'
                            truncated = True
                        if current in files_map:
                            files_map[current]['patch'] = p
                            files_map[current]['patch_truncated'] = truncated
                for line in pr.stdout.splitlines():
                    m = re.match(r'^diff --git a/(.+) b/(.+)$', line)
                    if m:
                        flush()
                        current = m.group(2)
                        buf = [line]
                    else:
                        buf.append(line)
                flush()
        except Exception:
            pass  # patches optional

    files = list(files_map.values())
    total_add = sum((f.get('additions') or 0) for f in files)
    total_del = sum((f.get('deletions') or 0) for f in files)
    return {
        'success': True,
        'repoPath': repo_path,
        'sha': full_sha,
        'short_sha': full_sha[:10],
        'subject': subject,
        'body': body,
        'author': author,
        'author_email': author_email,
        'author_unix': author_ts,
        'committer': committer,
        'committer_unix': committer_ts,
        'parents': parents,
        'stats': {'total_additions': total_add, 'total_deletions': total_del, 'files_changed': len(files)},
        'files': files,
    }

