def execute(params):
    import subprocess, os, re
    repo_path = params.get('repoPath') or os.getcwd()
    path = (params.get('path') or '').strip()
    if not path:
        return {'success': False, 'error': 'path required'}
    if not os.path.isdir(repo_path):
        return {'success': False, 'error': 'repoPath not a directory: ' + str(repo_path)}
    ref = (params.get('ref') or '').strip()
    line_start = params.get('line_start')
    line_end = params.get('line_end')
    max_lines = int(params.get('max_lines') or 500)
    if path:
        if path.startswith('/'):
            rp = os.path.realpath(repo_path).rstrip('/')
            pp = os.path.realpath(path)
            if pp == rp:
                path = '.'
            elif pp.startswith(rp + '/'):
                path = pp[len(rp) + 1:]
            else:
                return {'success': False, 'error': 'path must be repo-relative (e.g. "src/app.py" or "."), not absolute: ' + path}
    cmd = ['git', '-C', repo_path, 'blame', '--line-porcelain']
    if line_start and line_end:
        cmd += ['-L', str(line_start) + ',' + str(line_end)]
    elif line_start:
        cmd += ['-L', str(line_start) + ',+' + str(max_lines)]
    if ref:
        cmd.append(ref)
    cmd += ['--', path]
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=60)
    except Exception as e:
        return {'success': False, 'error': 'blame failed: ' + str(e)}
    if r.returncode != 0:
        return {'success': False, 'error': 'git blame: ' + (r.stderr or r.stdout)[:400]}

    # Parse --line-porcelain: each line-block starts with "<sha> <orig-line> <final-line> <count>"
    # followed by header fields and a "\t<actual line>".
    lines = []
    commits_seen = {}
    cur = None
    for ln in r.stdout.splitlines():
        m = re.match(r'^([0-9a-f]{40})\s+(\d+)\s+(\d+)', ln)
        if m:
            cur = {'sha': m.group(1)[:10], 'full_sha': m.group(1),
                   'source_line': int(m.group(2)), 'final_line': int(m.group(3)),
                   'author': None, 'author_mail': None, 'author_time': None, 'summary': None, 'content': None}
            continue
        if cur is None:
            continue
        if ln.startswith('author '):
            cur['author'] = ln[7:]
        elif ln.startswith('author-mail '):
            cur['author_mail'] = ln[12:].strip('<>')
        elif ln.startswith('author-time '):
            try:
                cur['author_time'] = int(ln[12:])
            except Exception:
                pass
        elif ln.startswith('summary '):
            cur['summary'] = ln[8:]
        elif ln.startswith('\t'):
            cur['content'] = ln[1:]
            lines.append(cur)
            commits_seen.setdefault(cur['full_sha'], {'sha': cur['sha'], 'author': cur['author'], 'summary': cur['summary']})
            cur = None
    truncated = False
    if len(lines) > max_lines:
        lines = lines[:max_lines]
        truncated = True
    return {
        'success': True,
        'repoPath': repo_path,
        'path': path,
        'ref': ref or 'HEAD',
        'line_start': line_start,
        'line_end': line_end,
        'count': len(lines),
        'truncated': truncated,
        'unique_commits': len(commits_seen),
        'lines': lines,
    }

def execute(params):
    """Recursively grep file contents for a pattern."""
    import os, re, fnmatch

    directory = params.get('directory') or params.get('dirPath') or '.'
    pattern = params.get('pattern')
    if pattern is None or pattern == '':
        return {'success': False, 'error': 'pattern parameter is required'}
    use_regex = bool(params.get('regex', False))
    file_pattern = params.get('filePattern') or params.get('glob') or '*'
    ignore_case = bool(params.get('ignoreCase', False))
    context = int(params.get('context') or 0)
    max_results = int(params.get('maxResults') or 200)
    exclude_dirs = set(params.get('excludeDirs') or ['.git', 'node_modules', '__pycache__', '.venv', 'venv', 'dist', 'build', '.next', '.cache', '.build-state'])

    if not os.path.isdir(directory):
        return {'success': False, 'error': 'directory not found: ' + str(directory)}

    flags = re.IGNORECASE if ignore_case else 0
    if use_regex:
        try:
            rx = re.compile(pattern, flags)
        except re.error as e:
            return {'success': False, 'error': 'invalid regex: ' + str(e)}
    else:
        rx = re.compile(re.escape(pattern), flags)

    hits = []
    truncated = False
    files_scanned = 0
    for root, dirs, files in os.walk(directory):
        dirs[:] = [d for d in dirs if d not in exclude_dirs and not d.startswith('.git')]
        for fname in files:
            if not fnmatch.fnmatch(fname, file_pattern):
                continue
            full = os.path.join(root, fname)
            try:
                if os.path.getsize(full) > 5 * 1024 * 1024:
                    continue
                with open(full, 'r', encoding='utf-8', errors='replace') as f:
                    lines = f.readlines()
            except Exception:
                continue
            files_scanned += 1
            for i, ln in enumerate(lines):
                if rx.search(ln):
                    hit = {'path': full, 'line': i + 1, 'text': ln.rstrip('\n')}
                    if context > 0:
                        s = max(0, i - context)
                        e = min(len(lines), i + context + 1)
                        hit['context'] = ''.join(lines[s:e]).rstrip('\n')
                        hit['contextStart'] = s + 1
                    hits.append(hit)
                    if len(hits) >= max_results:
                        truncated = True
                        break
            if truncated:
                break
        if truncated:
            break

    return {'success': True, 'pattern': pattern, 'directory': directory, 'filesScanned': files_scanned, 'count': len(hits), 'truncated': truncated, 'hits': hits}

def execute(params):
    """Replace a specific line range in a file."""
    import os

    file_path = params.get('filePath') or params.get('path')
    if not file_path:
        return {'success': False, 'error': 'filePath parameter is required'}
    if not os.path.isfile(file_path):
        return {'success': False, 'error': 'file not found: ' + file_path}

    start_line = params.get('startLine')
    end_line = params.get('endLine')
    new_content = params.get('newContent', '')

    if start_line is None:
        return {'success': False, 'error': 'startLine parameter is required'}
    try:
        start_line = int(start_line)
        end_line = int(end_line) if end_line is not None else start_line
    except (TypeError, ValueError):
        return {'success': False, 'error': 'startLine and endLine must be integers'}
    if start_line < 1:
        return {'success': False, 'error': 'startLine must be >= 1'}

    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            lines = f.readlines()
    except Exception as e:
        return {'success': False, 'error': str(e)}

    original_count = len(lines)

    # Insert mode: startLine == endLine + 1 means insert at startLine without removing anything
    is_insert = end_line == start_line - 1
    if not is_insert and end_line < start_line:
        return {'success': False, 'error': 'endLine must be >= startLine (or startLine - 1 for insert mode)'}
    if start_line > original_count + 1:
        return {'success': False, 'error': 'startLine ' + str(start_line) + ' exceeds file length ' + str(original_count)}

    # Normalize newContent to end with newline
    new_lines = new_content.splitlines(keepends=True)
    if new_lines and not new_lines[-1].endswith('\n'):
        new_lines[-1] += '\n'
    elif not new_lines and not is_insert:
        # Empty replacement = pure delete
        pass

    if is_insert:
        result = lines[:start_line - 1] + new_lines + lines[start_line - 1:]
        replaced_count = 0
    else:
        result = lines[:start_line - 1] + new_lines + lines[end_line:]
        replaced_count = end_line - start_line + 1

    try:
        with open(file_path, 'w', encoding='utf-8') as f:
            f.writelines(result)
    except Exception as e:
        return {'success': False, 'error': 'write failed: ' + str(e)}

    preview_start = max(0, start_line - 2)
    preview_end = min(len(result), start_line - 1 + len(new_lines) + 1)
    preview = ''.join('{:>5}: {}'.format(i + 1, result[i]) for i in range(preview_start, preview_end))

    return {
        'success': True,
        'filePath': file_path,
        'mode': 'insert' if is_insert else 'replace',
        'linesReplaced': replaced_count,
        'linesAdded': len(new_lines),
        'originalLineCount': original_count,
        'newLineCount': len(result),
        'preview': preview
    }

def execute(params):
    '''Extract text/elements from HTML using CSS selectors.'''
    html = params.get('html') or params.get('htmlString') or params.get('content')
    if not html or not isinstance(html, str):
        return {'success': False, 'error': 'html parameter is required (string)'}
    selector = params.get('selector') or params.get('cssSelector')
    attribute = params.get('attribute')   # if set, return this attr instead of text
    limit = int(params.get('limit') or 50)
    try:
        from bs4 import BeautifulSoup
    except ImportError:
        return {'success': False, 'error': 'BeautifulSoup (bs4) is not installed in the webapp image'}
    try:
        soup = BeautifulSoup(html, 'lxml')
    except Exception:
        soup = BeautifulSoup(html, 'html.parser')

    title = (soup.title.string.strip() if soup.title and soup.title.string else None)
    meta = {}
    for m in soup.find_all('meta'):
        k = m.get('name') or m.get('property')
        v = m.get('content')
        if k and v and k not in meta:
            meta[k] = v[:500]
    links = []
    for a in soup.find_all('a', href=True)[:limit]:
        links.append({'text': (a.get_text(strip=True) or '')[:200], 'href': a['href']})

    if selector:
        try:
            els = soup.select(selector)[:limit]
        except Exception as e:
            return {'success': False, 'error': f'Invalid selector: {e}'}
        out = []
        for el in els:
            if attribute:
                out.append(el.get(attribute))
            else:
                out.append({
                    'tag': el.name,
                    'text': el.get_text(' ', strip=True)[:1000],
                    'attrs': {k: (v if isinstance(v, str) else ' '.join(v))[:200] for k, v in el.attrs.items()},
                })
        return {'success': True, 'selector': selector, 'matchCount': len(out), 'matches': out,
                'title': title, 'meta': meta}

    text = soup.get_text(' ', strip=True)
    if len(text) > 12000:
        text = text[:12000] + '... [truncated]'
    return {'success': True, 'title': title, 'meta': meta, 'text': text,
            'linkCount': len(soup.find_all('a', href=True)), 'links': links}

def execute(params):
    '''Parse XML to a nested dict structure.'''
    xml = params.get('xml') or params.get('xmlString') or params.get('content')
    if not xml or not isinstance(xml, str):
        return {'success': False, 'error': 'xml parameter is required (string)'}
    import xml.etree.ElementTree as ET
    def to_dict(el):
        d = {}
        if el.attrib:
            d['@attrs'] = dict(el.attrib)
        children = list(el)
        if children:
            for c in children:
                cd = to_dict(c)
                tag = c.tag.split('}', 1)[-1]
                if tag in d:
                    if not isinstance(d[tag], list):
                        d[tag] = [d[tag]]
                    d[tag].append(cd)
                else:
                    d[tag] = cd
        text = (el.text or '').strip()
        if text:
            if d:
                d['#text'] = text
            else:
                return text
        return d if d else None
    try:
        root = ET.fromstring(xml)
    except ET.ParseError as e:
        return {'success': False, 'error': f'Invalid XML: {e}'}
    tag = root.tag.split('}', 1)[-1]
    return {'success': True, 'root': tag, 'data': {tag: to_dict(root)}}

def execute(params):
    '''Parse YAML to Python data structure.'''
    text = params.get('yaml') or params.get('yamlString') or params.get('content')
    if not text or not isinstance(text, str):
        return {'success': False, 'error': 'yaml parameter is required (string)'}
    try:
        import yaml
    except ImportError:
        return {'success': False, 'error': 'PyYAML is not installed in the webapp image'}
    try:
        docs = list(yaml.safe_load_all(text))
    except yaml.YAMLError as e:
        return {'success': False, 'error': f'Invalid YAML: {e}'}
    if len(docs) == 1:
        return {'success': True, 'data': docs[0], 'documents': 1}
    return {'success': True, 'data': docs, 'documents': len(docs)}

